import{_ as r,o as e,c as a,ae as n}from"./chunks/framework.Dzr56EFm.js";const c=JSON.parse('{"title":"设计趋势 - 2026-04-05","description":"","frontmatter":{"date":"2026-04-05T00:00:00.000Z","category":"UX Trend"},"headers":[],"relativePath":"daily/2026-04-05-uxtrend.md","filePath":"daily/2026-04-05-uxtrend.md"}'),o={name:"daily/2026-04-05-uxtrend.md"};function s(i,t,g,p,h,d){return e(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="设计趋势-2026-04-05" tabindex="-1">设计趋势 - 2026-04-05 <a class="header-anchor" href="#设计趋势-2026-04-05" aria-label="Permalink to &quot;设计趋势 - 2026-04-05&quot;">​</a></h1><blockquote><p>AI交互方式、Prompt UX、Agent UX、Workflow</p></blockquote><h2 id="今日概览" tabindex="-1">今日概览 <a class="header-anchor" href="#今日概览" aria-label="Permalink to &quot;今日概览&quot;">​</a></h2><p>今日设计趋势领域重点关注代理式UX和ChatGPT App SDK。代理式UX通过AI代理与用户协作，革新设计方法；而ChatGPT App SDK允许开发者在聊天中构建应用，为用户体验设计带来新可能。这两个动态最值得关注，预示着设计领域的AI融合趋势。</p><hr><h3 id="_1-为什么代理式ux将改变你对设计的所有认知" tabindex="-1">1. 为什么代理式UX将改变你对设计的所有认知 <a class="header-anchor" href="#_1-为什么代理式ux将改变你对设计的所有认知" aria-label="Permalink to &quot;1. 为什么代理式UX将改变你对设计的所有认知&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/generative-ai-revolution-ai-native-transformation/why-agentic-ux-will-change-everything-you-know-about-design-0394486f5add" target="_blank" rel="noreferrer">Why Agentic UX Will Change Everything You Know About Design</a></p><p><strong>一句话摘要</strong>: 代理式UX是一种AI代理与用户共同决策和协作的设计方法。</p><p><strong>能解决什么问题</strong>: 解决传统设计中缺乏个性化和主动性的问题。</p><p><strong>产品应用</strong>: 可应用于智能助手和自动化服务，提升用户体验和效率。</p><p><strong>示例场景</strong>: 智能助手根据用户习惯自动调整日程安排。</p><hr><h3 id="_2-提示设计-最佳实践" tabindex="-1">2. 提示设计：最佳实践 <a class="header-anchor" href="#_2-提示设计-最佳实践" aria-label="Permalink to &quot;2. 提示设计：最佳实践&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/@mohammednavazpv01/prompt-design-best-practices-6e6538dc99ee" target="_blank" rel="noreferrer">Prompt Design : best Practices - Medium</a></p><p><strong>一句话摘要</strong>: 推荐简洁、明确、具体的提示设计。</p><p><strong>能解决什么问题</strong>: 解决用户理解任务和执行操作的困难。</p><p><strong>产品应用</strong>: 适用于任何需要用户输入的场景，如搜索引擎、聊天机器人。</p><p><strong>示例场景</strong>: 搜索引擎中的简洁搜索提示。</p><hr><h3 id="_3-用户体验设计师的提示工程指南" tabindex="-1">3. 用户体验设计师的提示工程指南 <a class="header-anchor" href="#_3-用户体验设计师的提示工程指南" aria-label="Permalink to &quot;3. 用户体验设计师的提示工程指南&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/design-bootcamp/the-ux-designers-guide-to-prompt-engineering-from-first-prompt-to-finished-product-9fbca77f3175" target="_blank" rel="noreferrer">The UX Designer&#39;s Guide to Prompt Engineering - Medium</a></p><p><strong>一句话摘要</strong>: 将UX设计技能应用于AI系统的提示工程。</p><p><strong>能解决什么问题</strong>: 如何使AI系统更好地响应清晰的上下文、具体要求和结构化请求。</p><p><strong>产品应用</strong>: 可以将UX设计系统应用于AI提示模式，以提高设计工作的质量。</p><p><strong>示例场景</strong>: 在StyleHub结账流程中优化用户提示。</p><hr><h3 id="_4-在chatgpt中直接构建应用的新app-sdk" tabindex="-1">4. 在ChatGPT中直接构建应用的新App SDK <a class="header-anchor" href="#_4-在chatgpt中直接构建应用的新app-sdk" aria-label="Permalink to &quot;4. 在ChatGPT中直接构建应用的新App SDK&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/@kenzic/build-apps-directly-inside-chatgpt-with-the-new-app-sdk-e789ef0b5997" target="_blank" rel="noreferrer">Build Apps Directly Inside ChatGPT with the New App SDK - Medium</a></p><p><strong>一句话摘要</strong>: ChatGPT App SDK允许开发者在聊天中直接构建应用</p><p><strong>能解决什么问题</strong>: 将聊天界面转变为应用开发环境，实现交互式UI</p><p><strong>产品应用</strong>: 可以应用于需要即时交互和视觉展示的应用开发</p><p><strong>示例场景</strong>: 在聊天中直接展示和编辑HTML和JavaScript应用</p><hr><h3 id="_5-ux设计师的提示指南" tabindex="-1">5. UX设计师的提示指南 <a class="header-anchor" href="#_5-ux设计师的提示指南" aria-label="Permalink to &quot;5. UX设计师的提示指南&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://uxdesign.cc/a-ux-designer-guide-to-prompt-f045cd839489" target="_blank" rel="noreferrer">A UX designer guide to prompt - UX Collective</a></p><p><strong>一句话摘要</strong>: UX设计师通过构建提示帮助AI模型理解人类请求。</p><p><strong>能解决什么问题</strong>: 解决人类与机器之间沟通理解的障碍。</p><p><strong>产品应用</strong>: 可以应用，通过优化AI模型的提示来提升交互体验。</p><p><strong>示例场景</strong>: 设计一个聊天机器人，使其更自然地理解用户指令。</p><hr><h3 id="_6-提示工程-新ux技能" tabindex="-1">6. 提示工程：新UX技能 <a class="header-anchor" href="#_6-提示工程-新ux技能" aria-label="Permalink to &quot;6. 提示工程：新UX技能&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/@katyneale/prompt-engineering-is-the-new-ux-skill-b3a58cb00e14" target="_blank" rel="noreferrer">Prompt Engineering is the New UX Skill | by Designed to Diverge</a></p><p><strong>一句话摘要</strong>: 通过界面设计和逐步披露来构建更好的提示。</p><p><strong>能解决什么问题</strong>: 如何引导用户选择更好的AI提示而不让他们意识到自己在进行提示工程。</p><p><strong>产品应用</strong>: 可以应用到实际产品中，通过设计系统使对话直观，提供示例提示和模板。</p><p><strong>示例场景</strong>: 心脏外科医生和软件工程师使用同一AI工具时需要不同的提示方法。</p><hr><h3 id="_7-从产品到系统-代理型ai的转变" tabindex="-1">7. 从产品到系统：代理型AI的转变 <a class="header-anchor" href="#_7-从产品到系统-代理型ai的转变" aria-label="Permalink to &quot;7. 从产品到系统：代理型AI的转变&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://uxdesign.cc/from-products-to-systems-the-agentic-ai-shift-eaf6a7180c43" target="_blank" rel="noreferrer">From products to systems: The agentic AI shift - UX Collective</a></p><p><strong>一句话摘要</strong>: 设计需适应人类与代理合作的新范式。</p><p><strong>能解决什么问题</strong>: 如何确保代理生成的界面保持一致性、可访问性和品牌一致性。</p><p><strong>产品应用</strong>: 适用于需要代理与人类协作的企业平台，通过创建代理可消费的基础工件来实现。</p><p><strong>示例场景</strong>: DataRobot将设计文件翻译成代理可理解的markdown文件。</p><hr><h3 id="_8-向代理型用户体验的转变-为我思考" tabindex="-1">8. 向代理型用户体验的转变：为我思考 <a class="header-anchor" href="#_8-向代理型用户体验的转变-为我思考" aria-label="Permalink to &quot;8. 向代理型用户体验的转变：为我思考&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/@dirkjankraan/the-shift-to-agentic-ux-do-the-thinking-for-me-55b68b289de9" target="_blank" rel="noreferrer">The shift to agentic UX: do the thinking for me | by Dirkjan Kraan</a></p><p><strong>一句话摘要</strong>: 探讨如何从传统功能驱动软件转向代理型UI模式。</p><p><strong>能解决什么问题</strong>: 解决用户与系统交互时的思考负担。</p><p><strong>产品应用</strong>: 可应用于自动化任务和决策支持产品，提高效率。</p><p><strong>示例场景</strong>: 智能助手自动提醒用户每日待办事项。</p><hr><h3 id="_9-ai代理在用户体验中的应用-为何我如此着迷" tabindex="-1">9. AI代理在用户体验中的应用：为何我如此着迷 <a class="header-anchor" href="#_9-ai代理在用户体验中的应用-为何我如此着迷" aria-label="Permalink to &quot;9. AI代理在用户体验中的应用：为何我如此着迷&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/@david_zerbe/ai-agentic-usability-testing-why-im-hooked-after-25-years-in-ux-bad6ee0d7a78" target="_blank" rel="noreferrer">AI Agents in UX: Why I&#39;m Hooked (And You Might Be Too) Real Talk ...</a></p><p><strong>一句话摘要</strong>: AI代理通过模拟真实用户交互，帮助发现并改进设计问题。</p><p><strong>能解决什么问题</strong>: 传统UX工具无法模拟真实用户交互，难以发现设计盲点。</p><p><strong>产品应用</strong>: 可以应用于产品设计验证，通过AI代理测试发现并修复问题。</p><p><strong>示例场景</strong>: AI代理在注册流程中发现CTA对比度低，层次不清晰。</p><hr><h3 id="_10-agentic-ai、设计系统与figma-实用指南" tabindex="-1">10. Agentic AI、设计系统与Figma：实用指南 <a class="header-anchor" href="#_10-agentic-ai、设计系统与figma-实用指南" aria-label="Permalink to &quot;10. Agentic AI、设计系统与Figma：实用指南&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://uxdesign.cc/agentic-ai-design-systems-figma-a-practical-guide-6ab0b681718d" target="_blank" rel="noreferrer">Agentic AI, design systems &amp; Figma: a practical guide - UX Collective</a></p><p><strong>一句话摘要</strong>: Agentic AI通过Figma和Storybook理解设计行为，实现组件自动化。</p><p><strong>能解决什么问题</strong>: 设计到代码的转换过程中，如何确保组件状态和行为的一致性。</p><p><strong>产品应用</strong>: 适用于需要自动化设计系统和代码组件映射的产品开发。</p><p><strong>示例场景</strong>: 在开发评分系统时，确保五角星组件的不同状态被正确识别和使用。</p><hr>',75)])])}const m=r(o,[["render",s]]);export{c as __pageData,m as default};
